package pe.org.camaracomercioica.protestos; import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.boot.test.context.SpringBootTest; import org.springframework.security.oauth2.jose.jws.MacAlgorithm; import org.springframework.security.oauth2.jwt.*; import java.time.Instant; import static org.assertj.core.api.Assertions.assertThatThrownBy; @SpringBootTest class JwtValidationTest {@Autowired JwtEncoder encoder;@Autowired JwtDecoder decoder;@Test void rechazaTokenConIssuerDistinto(){var now=Instant.now();var claims=JwtClaimsSet.builder().issuer("otro-emisor").subject("user@test.local").issuedAt(now).expiresAt(now.plusSeconds(300)).build();var token=encoder.encode(JwtEncoderParameters.from(JwsHeader.with(MacAlgorithm.HS256).build(),claims)).getTokenValue();assertThatThrownBy(()->decoder.decode(token)).isInstanceOf(JwtValidationException.class);}}
